item.description:
Get structure member offset bytes You only need to include &lt;stddef.h&gt; to use offset or write the following code
#define offsetof(TYPE, MEMBER) ((size_t) &amp;((TYPE *)0)-&gt;MEMBER) &lt;stdbool.h&gt; You can use Booleans as long as you include &lt;stdbool.h&gt;
#ifndef _STDBOOL #define _STDBOOL  #define __bool_true_false_are_defined 1  #ifndef __cplusplus  #define bool _Bool #define false 0 #define true 1  #endif /* __cplusplus */ #endif /* _STDBOOL */
